        <div id="loading" style="display:none; text-align:center;">
            <p>⏳ Consultando registros oficiales...</p>
        </div>

        <div id="resultado"></div>

        <div class="legal-notice">
            <strong>Aviso de Seguridad:</strong> Esta plataforma permite la validación de documentos emitidos institucionalmente. Los datos mostrados corresponden a la información oficial registrada en nuestra base de datos. Para efectos legales en entidades públicas del Perú, este sistema cumple con los criterios de transparencia y acceso a la información según la normativa vigente del Estado.
        </div>
    </div>
</div>

<script>
    const URL_CERTIFICADOS = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vSvNLRnNnFr2K8XupkMGL6fqERIJRuLL2HijIViLn8Udah9IpwwuZmkw5hiRjmCb-lJ7rN0JgomCnUY/pub?output=xlsx';
    const URL_ACTIVACION = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vTPlmHnRLdNhhBjN6w1HOJJU5dDm5p9dfNpjwwvmprno-FQcWTq6jy1d2hVmXrl7sJRRIpG42BvBaoj/pub?output=xlsx';

    let sistemaActivo = false;

    async function verificarVigencia() {
        const pill = document.getElementById('statusPill');
        try {
            const res = await fetch(URL_ACTIVACION);
            const ab = await res.arrayBuffer();
            const wb = XLSX.read(ab, {type: 'buffer', cellDates: true});
            const data = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]], {header: 1});

            const fechaVencimiento = new Date(data[1][2]); // Celda C2
            const hoy = new Date();
            hoy.setHours(0,0,0,0);
            fechaVencimiento.setHours(0,0,0,0);

            if (hoy <= fechaVencimiento) {
                sistemaActivo = true;
                pill.innerText = "SISTEMA ACTIVO";
                pill.className = "status-pill status-active";
                document.getElementById('codigoInput').disabled = false;
                document.getElementById('btnValidar').disabled = false;
            } else {
                suspenderSistema();
            }
        } catch (e) {
            pill.innerText = "ERROR DE CONEXIÓN";
            pill.className = "status-pill status-expired";
        }
    }

    function suspenderSistema() {
        const pill = document.getElementById('statusPill');
        pill.innerText = "SISTEMA SUSPENDIDO";
        pill.className = "status-pill status-expired";
        document.getElementById('searchBar').innerHTML = "<div style='color:var(--error); font-weight:bold; text-align:center; width:100%; border: 1px dashed var(--error); padding: 15px; border-radius: 8px;'>ACCESO SUSPENDIDO</div>";
    }

    async function validarCertificado() {
        const codigo = document.getElementById('codigoInput').value.trim();
        const resDiv = document.getElementById('resultado');
        const loading = document.getElementById('loading');

        if (!codigo) return;

        resDiv.innerHTML = "";
        loading.style.display = 'block';

        try {
            const res = await fetch(URL_CERTIFICADOS);
            const ab = await res.arrayBuffer();
            const wb = XLSX.read(ab, {type: 'buffer', cellDates: true});
            const data = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);

            const headers = Object.keys(data[0]);
            const colA = headers[0];
            const registro = data.find(r => String(r[colA]).toLowerCase() === codigo.toLowerCase());

            if (registro) {
                let itemsHtml = '';
                for (let i = 1; i <= 6; i++) {
                    const h = headers[i];
                    let val = registro[h] || '---';
                    if (val instanceof Date) val = val.toLocaleDateString('es-PE');
                    itemsHtml += `<div class="data-box"><span class="label">${h}</span><span class="value">${val}</span></div>`;
                }

                resDiv.innerHTML = `
                    <div class="result-card valid-bg">
                        <div class="result-title" style="color: var(--success);">✅ CERTIFICADO VÁLIDO</div>
                        <div class="data-grid">${itemsHtml}</div>
                    </div>`;
            } else {
                resDiv.innerHTML = `
                    <div class="result-card invalid-bg">
                        <div class="result-title" style="color: var(--error);">⚠️ ESTE CÓDIGO NO EXISTE</div>
                        <p style="font-size: 14px; color: #991b1b;">El código ingresado no figura en nuestra base de datos oficial.</p>
                    </div>`;
            }
        } catch (e) {
            resDiv.innerHTML = "<p>Error técnico al procesar la solicitud.</p>";
        } finally {
            loading.style.display = 'none';
        }
    }
</script>

</body>
</html>

