// Lógica de Validación de Certificados
async function checkVigencia() {
  try {
    const res = await fetch(URL_ACTIVACION);
    const ab = await res.arrayBuffer();
    const wb = XLSX.read(ab, { type: 'buffer', cellDates: true });
    const data = XLSX.utils.sheet_to_json<any[]>(wb.Sheets[wb.SheetNames[0]], { header: 1 });

    const fechaVencimiento = new Date(data[1][2]); // Celda C2
    const hoy = new Date();
    hoy.setHours(0,0,0,0);
    fechaVencimiento.setHours(0,0,0,0);

    if (hoy <= fechaVencimiento) {
      systemStatus = 'active';
      if (systemStatusContainer) systemStatusContainer.innerHTML = `
        <span class="bg-green-50 text-green-600 border border-green-100 px-6 py-2 rounded-full text-[10px] font-bold">
          <i class="fa-solid fa-circle-check mr-2"></i> SISTEMA ACTIVO Y VIGENTE
        </span>`;
    } else {
      systemStatus = 'expired';
      renderSystemOff();
    }
  } catch (e) {
    systemStatus = 'error';
    renderSystemOff();
  }
}

function renderSystemOff() {
  if (systemStatusContainer) systemStatusContainer.innerHTML = `
    <span class="bg-red-50 text-red-600 border border-red-100 px-6 py-2 rounded-full text-[10px] font-bold">
      <i class="fa-solid fa-circle-exclamation mr-2"></i> ACCESO RESTRINGIDO (CONSULTAR CON SOPORTE)
    </span>`;
  const btn = document.getElementById('cert-btn') as HTMLButtonElement;
  if (btn) btn.disabled = true;
}

certForm?.addEventListener('submit', async (e) => {
  e.preventDefault();
  if (systemStatus !== 'active') return;

  const codigo = certInput.value.trim().toLowerCase();
  const btn = document.getElementById('cert-btn') as HTMLButtonElement;
  btn.innerHTML = '<i class="fa-solid fa-circle-notch animate-spin"></i><span>PROCESANDO...</span>';
  btn.disabled = true;

  try {
    const res = await fetch(URL_CERTIFICADOS);
    const ab = await res.arrayBuffer();
    const wb = XLSX.read(ab, { type: 'buffer' });
    const data = XLSX.utils.sheet_to_json<any>(wb.Sheets[wb.SheetNames[0]]);

    const headers = Object.keys(data[0]);
    const registro = data.find(r => String(r[headers[0]]).toLowerCase() === codigo);

    if (certResults) {
      certResults.classList.remove('hidden');
      if (registro) {
        let rows = '';
        // Mostramos las primeras 6 columnas informativas del Excel
        for (let i = 1; i <= 6; i++) {
          const h = headers[i] || 'Campo';
          let v = registro[h] || '---';
          rows += `
            <div class="border-b border-slate-100 pb-2">
              <span class="block text-[9px] uppercase font-bold text-slate-400 tracking-widest mb-1">${h}</span>
              <span class="block font-bold text-slate-700">${v}</span>
            </div>`;
        }
        certResults.innerHTML = `
          <div class="bg-brand-blue/[0.02] border border-brand-blue/10 rounded-3xl p-6 md:p-10 space-y-8 animate-fade-in-up mt-8">
            <div class="flex items-center space-x-4">
              <div class="w-12 h-12 bg-green-100 text-green-600 rounded-2xl flex items-center justify-center text-xl">
                <i class="fa-solid fa-shield-check"></i>
              </div>
              <div>
                <h5 class="text-xl font-bold text-slate-900">Documento Verificado</h5>
                <p class="text-green-600 text-xs font-bold uppercase tracking-widest">Validado en Base de Datos Oficial</p>
              </div>
            </div>
            <div class="grid sm:grid-cols-2 gap-x-10 gap-y-6">${rows}</div>
          </div>`;
      } else {
        certResults.innerHTML = `
          <div class="bg-white border border-red-100 rounded-3xl p-8 text-center space-y-4 shadow-lg animate-fade-in-up mt-8">
            <div class="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto text-2xl">
              <i class="fa-solid fa-search-minus"></i>
            </div>
            <h5 class="text-xl font-bold text-red-900 uppercase">Sin resultados</h5>
            <p class="text-slate-500 text-sm">El código ingresado no figura en nuestros registros actuales. Verifique e intente nuevamente.</p>
          </div>`;
      }
      // Scroll automático a resultados si es móvil
      if (window.innerWidth < 768) {
        certResults.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
    }
  } catch (err) {
    alert("Ocurrió un error al conectar con el servidor de datos.");
  } finally {
    btn.innerHTML = '<i class="fa-solid fa-magnifying-glass"></i><span>VALIDAR</span>';
    btn.disabled = false;
  }
});

