// Función de utilidad para fetch con timeout
async function fetchWithTimeout(resource: string, options: any = {}) {
  const { timeout = 8000 } = options;
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), timeout);
  const response = await fetch(resource, {
    ...options,
    signal: controller.signal,
    mode: 'cors',
    cache: 'no-cache'
  });
  clearTimeout(id);
  return response;
}

// Lógica de Validación de Certificados
async function checkVigencia() {
  try {
    const res = await fetchWithTimeout(URL_ACTIVACION);
    const ab = await res.arrayBuffer();
    const wb = XLSX.read(new Uint8Array(ab), { type: 'array', cellDates: true });
    const data = XLSX.utils.sheet_to_json<any[]>(wb.Sheets[wb.SheetNames[0]], { header: 1 });

    if (!data || data.length < 2) throw new Error("Datos de activación insuficientes");

    const fechaVencimiento = new Date(data[1][2]); // Celda C2
    const hoy = new Date();
    hoy.setHours(0,0,0,0);
    fechaVencimiento.setHours(0,0,0,0);

    if (hoy <= fechaVencimiento) {
      systemStatus = 'active';
      if (systemStatusContainer) {
        systemStatusContainer.innerHTML = `
          <span class="bg-green-50 text-green-600 border border-green-100 px-6 py-2 rounded-full text-[10px] font-bold">
            <i class="fa-solid fa-circle-check mr-2"></i> SISTEMA ACTIVO Y VIGENTE
          </span>`;
      }
    } else {
      systemStatus = 'expired';
      renderSystemOff("LICENCIA EXPIRADA");
    }
  } catch (e) {
    console.error("Error sincronizando vigencia:", e);
    systemStatus = 'error';
    renderSystemOff("ERROR DE CONEXIÓN");
  }
}

function renderSystemOff(motivo: string) {
  if (systemStatusContainer) {
    systemStatusContainer.innerHTML = `
      <span class="bg-red-50 text-red-600 border border-red-100 px-6 py-2 rounded-full text-[10px] font-bold">
        <i class="fa-solid fa-circle-exclamation mr-2"></i> ${motivo} (CONSULTAR SOPORTE)
      </span>`;
  }
  const btn = document.getElementById('cert-btn') as HTMLButtonElement;
  if (btn) {
    btn.disabled = true;
    btn.classList.add('opacity-50', 'cursor-not-allowed');
  }
}

