      }
      // Scroll automático al resultado en móviles
      if (window.innerWidth < 768) {
        certResults.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
    }
  } catch (err) {
    console.error("Error validando certificado:", err);
    alert("Error al conectar con la base de datos institucional. Por favor, intente más tarde.");
  } finally {
    btn.innerHTML = '<i class="fa-solid fa-magnifying-glass"></i><span>VALIDAR</span>';
    btn.disabled = false;
  }
});

