/**
 * Función de fetch con Timeout y Retry para mayor robustez en VPS
 */
async function fetchWithRetry(url: string, retries = 2, timeout = 7000): Promise<Response> {
  for (let i = 0; i < retries; i++) {
    try {
      const controller = new AbortController();
      const id = setTimeout(() => controller.abort(), timeout);

      const response = await fetch(url, {
        signal: controller.signal,
        mode: 'cors',
        cache: 'no-store', // Importante para evitar datos viejos en VPS
        headers: {
          'Accept': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
        }
      });

      clearTimeout(id);
      if (response.ok) return response;
    } catch (err) {
      console.warn(`Intento ${i + 1} fallido para ${url}:`, err);
      if (i === retries - 1) throw err;
      await new Promise(r => setTimeout(r, 1000)); // Esperar 1s antes de reintentar
    }
  }
  throw new Error(`No se pudo conectar con el servidor después de ${retries} intentos.`);
}

// Lógica de Validación de Certificados
async function checkVigencia() {
  console.log("Iniciando sincronización de vigencia...");
  try {
    const res = await fetchWithRetry(URL_ACTIVACION);
    const ab = await res.arrayBuffer();

    // Usamos un bloque try-catch interno para la lectura del Excel
    let data;
    try {
      const wb = XLSX.read(new Uint8Array(ab), { type: 'array', cellDates: true });
      data = XLSX.utils.sheet_to_json<any[]>(wb.Sheets[wb.SheetNames[0]], { header: 1 });
    } catch (xlsxErr) {
      console.error("Error al procesar el archivo Excel:", xlsxErr);
      throw new Error("Formato de datos inválido");
    }

    if (!data || data.length < 2) throw new Error("Datos de activación insuficientes");

    const fechaVencimiento = new Date(data[1][2]); // Celda C2
    const hoy = new Date();
    hoy.setHours(0,0,0,0);
    fechaVencimiento.setHours(0,0,0,0);

    console.log("Vigencia comprobada:", { hoy, vence: fechaVencimiento });

    if (hoy <= fechaVencimiento) {
      systemStatus = 'active';
      if (systemStatusContainer) {
        systemStatusContainer.innerHTML = `
          <span class="bg-green-100 text-green-700 border border-green-200 px-6 py-2 rounded-full text-[10px] font-bold">
            <i class="fa-solid fa-circle-check mr-2"></i> SISTEMA SINCRONIZADO
          </span>`;
      }
    } else {
      systemStatus = 'expired';
      renderSystemOff("LICENCIA EXPIRADA");
    }
  } catch (e) {
    console.error("Error crítico en checkVigencia:", e);
    systemStatus = 'error';
    renderSystemOff("ERROR DE RED / CORS");
  }
}

